import React, { useState } from 'react';
import './Register.css';

function Register() {
  const [isLoginMode, setIsLoginMode] = useState(false); // Режим входа или регистрации
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [status, setStatus] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    // Выбираем путь в зависимости от режима
    const endpoint = isLoginMode ? "/api/login" : "/api/register";
    
    try {
      const response = await fetch("http://localhost:5002" + endpoint, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ username, password })
      });

      const data = await response.json();
      setStatus(data.message);

      if (response.ok && isLoginMode) {
          // Тут в реальности сохраняют токен, но нам хватит и текста
          alert("Вход выполнен успешно!");
      }
    } catch (err) {
      setStatus("Проблемы со связью...");
    }
  };

  return (
    <div className="register-page">
      <div className="register-card">
        <h2>{isLoginMode ? "Личный кабинет" : "Стать частью стада"}</h2>
        
        <form onSubmit={handleSubmit} className="reg-form">
          <input 
            placeholder="Ваш никнейм" 
            value={username} 
            onChange={(e) => setUsername(e.target.value)} 
            required 
          />
          <input 
            type="password" 
            placeholder="Пароль" 
            value={password} 
            onChange={(e) => setPassword(e.target.value)} 
            required 
          />
          <button type="submit" className="btn-red">
            {isLoginMode ? "Войти" : "Зарегистрироваться"}
          </button>
        </form>

        <p className="status-msg">{status}</p>

        {/* ПЕРЕКЛЮЧАТЕЛЬ */}
        <button 
          className="btn-switch" 
          onClick={() => { setIsLoginMode(!isLoginMode); setStatus(""); }}
        >
          {isLoginMode ? "Нет аккаунта? Создать" : "Уже зарегистрирован? Войти"}
        </button>
      </div>
    </div>
  );
}

export default Register;
